class Solution {
public:
    long long repairCars(vector<int>& ranks, int cars) {
        long long left = 0, right = 1e14;
        while (left < right) {
            long long mid = left + (right - left) / 2;
            long long count = 0;
            for (int rank : ranks) {
                count += sqrt(mid / rank);
            }
            if (count < cars) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
};
```
